using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Sub-painel "Mudar controles" da secção Opções (Menu de Pausa, Tarefa #12).
///
/// Lista uma <see cref="RebindRowUI"/> por acção/binding rebinding-ável (Mover,
/// Saltar, Atacar, Interagir, Habilidade, Pausa, etc. — configurado no
/// Editor). "Restaurar predefinições" remove todos os overrides. Os overrides
/// são persistidos em PlayerPrefs (JSON via Input System), separado de
/// SaveData — tal como GameSettings, é uma preferência do dispositivo/perfil.
///
/// Fecha com o botão "Voltar" (UI) OU com "B"/Escape/gamepad-East, via
/// <see cref="ICancelHandler"/> — o Input System UI Module invoca
/// automaticamente "OnCancel" no GameObject seleccionado quando a acção
/// "Cancel" dispara, cumprindo "o menu precisa funcionar perfeitamente por
/// comando e teclado".
///
/// Montagem no Editor:
/// - "actionsAsset": o InputActionAsset usado pelo PlayerInputRouter.
/// - "rows": uma RebindRowUI por binding que o jogador pode alterar.
/// - "backButton"/"resetButton": botões "Voltar"/"Restaurar predefinições".
/// </summary>
public class ControlsRebindSectionUI : MonoBehaviour, ICancelHandler
{
    [SerializeField] private GameObject root;
    [SerializeField] private InputActionAsset actionsAsset;
    [SerializeField] private List<RebindRowUI> rows = new List<RebindRowUI>();

    [SerializeField] private Button backButton;
    [SerializeField] private Button resetButton;

    [Tooltip("Primeiro elemento a seleccionar ao abrir este sub-painel.")]
    [SerializeField] private Selectable firstSelectable;

    private const string PrefKey = "input_binding_overrides";

    public GameObject Root => root != null ? root : gameObject;

    /// <summary>Disparado quando este sub-painel fecha (botão "Voltar" ou Cancel) — OptionsSectionUI usa isto para devolver a selecção à página principal.</summary>
    public event Action Closed;

    private void Awake()
    {
        if (backButton != null) backButton.onClick.AddListener(Close);
        if (resetButton != null) resetButton.onClick.AddListener(ResetAll);

        foreach (var row in rows)
            if (row != null) row.RebindCompleted += OnRowRebound;

        LoadOverrides();

        if (root != null) root.SetActive(false);
    }

    public void Open()
    {
        if (root != null) root.SetActive(true);

        foreach (var row in rows)
            row?.RefreshDisplay();

        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }

    public void Close()
    {
        if (root != null) root.SetActive(false);
        Closed?.Invoke();
    }

    /// <summary>Chamado automaticamente pelo Input System UI Module quando "Cancel" (B/Escape) dispara com este painel seleccionado.</summary>
    public void OnCancel(BaseEventData eventData) => Close();

    private void OnRowRebound(RebindRowUI row) => SaveOverrides();

    private void ResetAll()
    {
        if (actionsAsset != null) actionsAsset.RemoveAllBindingOverrides();
        PlayerPrefs.DeleteKey(PrefKey);
        PlayerPrefs.Save();

        foreach (var row in rows)
            row?.RefreshDisplay();
    }

    private void SaveOverrides()
    {
        if (actionsAsset == null) return;

        string json = actionsAsset.SaveBindingOverridesAsJson();
        PlayerPrefs.SetString(PrefKey, json);
        PlayerPrefs.Save();
    }

    private void LoadOverrides()
    {
        if (actionsAsset == null) return;

        string json = PlayerPrefs.GetString(PrefKey, string.Empty);
        if (!string.IsNullOrEmpty(json)) actionsAsset.LoadBindingOverridesFromJson(json);
    }
}
